func (v SpecValue) Equal(o attr.Value) bool {
	other, ok := o.(SpecValue)

	if !ok {
		return false
	}

	if v.state != other.state {
		return false
	}

	if v.state != attr.ValueStateKnown {
		return true
	}

	if !v.RouterKind.Equal(other.RouterKind) {
		return false
	}

	if !v.RouterSelectors.Equal(other.RouterSelectors) {
		return false
	}

	if !v.Routers.Equal(other.Routers) {
		return false
	}

	if !v.SearchList.Equal(other.SearchList) {
		return false
	}

	if !v.Servers.Equal(other.Servers) {
		return false
	}

	return true
}

